import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Box, Paper, Typography, TextField, Button, Alert, InputAdornment, IconButton } from '@mui/material';
import { EnvelopeIcon, LockClosedIcon, EyeIcon, EyeSlashIcon } from '@heroicons/react/24/outline';
import { motion } from 'framer-motion';
import { useAuth } from '../contexts/AuthContext';

const ADMIN_CREDENTIALS = {
  email: 'admin@hunterai.com',
  password: 'HunterAI2025!',
  id: 'admin-id',
  role: 'admin',
  name: 'Admin User'
};

const Login: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const { login } = useAuth();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    if (!email || !password) {
      setError('Email and password are required');
      setLoading(false);
      return;
    }

    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      setError('Invalid email format');
      setLoading(false);
      return;
    }

    try {
      if (email === ADMIN_CREDENTIALS.email && password === ADMIN_CREDENTIALS.password) {
        localStorage.setItem('token', 'admin-token');
        localStorage.setItem('user', JSON.stringify({
          id: ADMIN_CREDENTIALS.id,
          email: ADMIN_CREDENTIALS.email,
          role: ADMIN_CREDENTIALS.role,
          name: ADMIN_CREDENTIALS.name
        }));
        navigate('/admin/home');
      } else {
        await login(email, password);
        navigate('/applicant/home');
      }
    } catch (err: any) {
      setError(err.message || 'Failed to log in. Please check your credentials.');
    } finally {
      setLoading(false);
    }
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: { opacity: 1, transition: { duration: 0.3 } },
  };

  const buttonVariants = {
    hover: { scale: 1.05 },
    tap: { scale: 0.95 },
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        bgcolor: 'var(--dark-bg)',
        background: 'linear-gradient(135deg, #1e3a8a 0%, #1e1e3b 100%)',
        px: { xs: 1, sm: 2 },
        width: '100%',
      }}
    >
      <motion.div variants={containerVariants} initial="hidden" animate="visible">
        <Paper
          elevation={6}
          className="hunter-card"
          sx={{
            width: '100%',
            maxWidth: { xs: 320, sm: 360 },
            minWidth: { xs: 280 },
          }}
        >
          <Typography
            variant="h5"
            align="center"
            sx={{
              fontWeight: 'bold',
              mt: 2,
              mb: 1,
              background: 'linear-gradient(45deg, var(--primary-blue), var(--primary-purple))',
              WebkitBackgroundClip: 'text',
              WebkitTextFillColor: 'transparent',
            }}
          >
            HUNTER AI
          </Typography>
          <Typography
            variant="body2"
            color="var(--text-muted)"
            align="center"
            sx={{ mb: 2 }}
          >
            Your AI Interview Companion
          </Typography>

          {error && (
            <Alert
              severity="error"
              sx={{
                mb: 2,
                bgcolor: 'var(--error-bg)',
                color: 'var(--error-text)',
              }}
            >
              {error}
            </Alert>
          )}

          <form onSubmit={handleSubmit}>
            <TextField
              fullWidth
              label="Email Address"
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <EnvelopeIcon className="h-4 w-4" style={{ color: 'var(--primary-blue)' }} />
                  </InputAdornment>
                ),
              }}
              sx={{
                mb: 2,
                '& .MuiOutlinedInput-root': {
                  bgcolor: 'rgba(30, 41, 59, 0.5)',
                  color: 'var(--text-light)',
                  '& fieldset': { borderColor: 'var(--border-glow)' },
                  '&:hover fieldset': { borderColor: 'var(--primary-blue)' },
                  '&.Mui-focused fieldset': {
                    borderColor: 'var(--primary-blue)',
                    boxShadow: '0 0 8px rgba(59, 130, 246, 0.2)',
                  },
                },
                '& .MuiInputLabel-root': { color: 'var(--text-muted)' },
                '& .MuiInputLabel-root.Mui-focused': { color: 'var(--primary-blue)' },
              }}
            />
            <TextField
              fullWidth
              label="Password"
              type={showPassword ? 'text' : 'password'}
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <LockClosedIcon className="h-4 w-4" style={{ color: 'var(--primary-blue)' }} />
                  </InputAdornment>
                ),
                endAdornment: (
                  <InputAdornment position="end">
                    <IconButton
                      onClick={() => setShowPassword(!showPassword)}
                      edge="end"
                      sx={{ p: 0.5 }}
                    >
                      {showPassword ? (
                        <EyeSlashIcon className="h-4 w-4" style={{ color: 'var(--primary-blue)' }} />
                      ) : (
                        <EyeIcon className="h-4 w-4" style={{ color: 'var(--primary-blue)' }} />
                      )}
                    </IconButton>
                  </InputAdornment>
                ),
              }}
              sx={{
                mb: 2,
                '& .MuiOutlinedInput-root': {
                  bgcolor: 'rgba(30, 41, 59, 0.5)',
                  color: 'var(--text-light)',
                  '& fieldset': { borderColor: 'var(--border-glow)' },
                  '&:hover fieldset': { borderColor: 'var(--primary-blue)' },
                  '&.Mui-focused fieldset': {
                    borderColor: 'var(--primary-blue)',
                    boxShadow: '0 0 8px rgba(59, 130, 246, 0.2)',
                  },
                },
                '& .MuiInputLabel-root': { color: 'var(--text-muted)' },
                '& .MuiInputLabel-root.Mui-focused': { color: 'var(--primary-blue)' },
              }}
            />
            <Button
              component={motion.button}
              variants={buttonVariants}
              whileHover="hover"
              whileTap="tap"
              type="submit"
              fullWidth
              variant="contained"
              disabled={loading}
              className="hunter-button hunter-button-primary"
              sx={{ mb: 2, py: { xs: 1, sm: 1.2 } }}
            >
              {loading ? 'Logging in...' : 'Access HUNTER AI'}
            </Button>
            <Box
              sx={{
                display: 'flex',
                flexDirection: { xs: 'column', sm: 'row' },
                gap: { xs: 1, sm: 2 },
                justifyContent: 'center',
              }}
            >
              <Button
                component={motion.button}
                variants={buttonVariants}
                whileHover="hover"
                whileTap="tap"
                fullWidth
                variant="outlined"
                onClick={() => navigate('/register')}
                className="hunter-button hunter-button-secondary"
                sx={{ py: { xs: 0.75, sm: 1 } }}
              >
                Register
              </Button>
              <Button
                component={motion.button}
                variants={buttonVariants}
                whileHover="hover"
                whileTap="tap"
                fullWidth
                variant="outlined"
                onClick={() => navigate('/forgot-password')}
                className="hunter-button hunter-button-secondary"
                sx={{ py: { xs: 0.75, sm: 1 } }}
              >
                Forgot Password
              </Button>
            </Box>
          </form>
        </Paper>
      </motion.div>
    </Box>
  );
};

export default Login;
